import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { User, Mail, Lock, Sparkles, Eye, EyeOff, Check } from 'lucide-react';
import toast from 'react-hot-toast';
import { useAuth } from '../store/AuthContext';
import { authAPI } from '../utils/api';

const RegisterPage = () => {
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleChange = (e) =>
    setForm((prev) => ({ ...prev, [e.target.name]: e.target.value }));

  const passwordStrength = () => {
    const p = form.password;
    if (!p) return { score: 0, label: '', color: '' };
    let score = 0;
    if (p.length >= 6) score++;
    if (p.length >= 10) score++;
    if (/[A-Z]/.test(p)) score++;
    if (/[0-9]/.test(p)) score++;
    if (/[^A-Za-z0-9]/.test(p)) score++;
    if (score <= 1) return { score, label: 'Weak', color: 'var(--accent-secondary)' };
    if (score <= 3) return { score, label: 'Fair', color: 'var(--accent-yellow)' };
    return { score, label: 'Strong', color: 'var(--accent-green)' };
  };

  const strength = passwordStrength();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.name || !form.email || !form.password) {
      toast.error('Please fill in all fields.');
      return;
    }
    if (form.password.length < 6) {
      toast.error('Password must be at least 6 characters.');
      return;
    }
    setLoading(true);
    try {
      const { data } = await authAPI.register(form);
      login(data.token, data.user);
      toast.success('Account created! Welcome to AIStudio 🎉');
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Registration failed.');
    } finally {
      setLoading(false);
    }
  };

  const perks = [
    '10 free AI generations per month',
    'Resume & Blog generation',
    'PDF export included',
    'No credit card required',
  ];

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '24px',
      gap: '48px',
      flexWrap: 'wrap',
    }}>
      {/* Left: Perks */}
      <div className="fade-in" style={{ maxWidth: '320px', flex: '1 1 280px' }}>
        <div style={{
          width: '52px', height: '52px',
          background: 'var(--accent)',
          borderRadius: '14px',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          marginBottom: '20px',
          boxShadow: '0 0 30px var(--accent-glow)',
        }}>
          <Sparkles size={24} color="white" />
        </div>
        <h2 style={{ fontSize: '28px', marginBottom: '12px', letterSpacing: '-0.03em' }}>
          Start creating with AI today
        </h2>
        <p style={{ color: 'var(--text-secondary)', marginBottom: '28px', lineHeight: '1.6' }}>
          Join thousands of professionals using AIStudio to craft better resumes and blogs.
        </p>
        <ul style={{ listStyle: 'none', display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {perks.map((perk) => (
            <li key={perk} style={{ display: 'flex', alignItems: 'center', gap: '10px', fontSize: '14px', color: 'var(--text-secondary)' }}>
              <div style={{
                width: '20px', height: '20px', flexShrink: 0,
                background: 'rgba(67, 217, 162, 0.15)',
                borderRadius: '50%',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
              }}>
                <Check size={12} color="var(--accent-green)" />
              </div>
              {perk}
            </li>
          ))}
        </ul>
      </div>

      {/* Right: Form */}
      <div className="card fade-in fade-in-delay-1" style={{ width: '100%', maxWidth: '400px', flex: '1 1 340px' }}>
        <h1 style={{ fontSize: '22px', marginBottom: '24px' }}>Create your account</h1>

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '18px' }}>
          {/* Name */}
          <div>
            <label className="label" htmlFor="name">Full Name</label>
            <div style={{ position: 'relative' }}>
              <User size={16} style={{
                position: 'absolute', left: '14px', top: '50%',
                transform: 'translateY(-50%)', color: 'var(--text-muted)',
              }} />
              <input
                id="name"
                className="input"
                type="text"
                name="name"
                placeholder="Jane Smith"
                value={form.name}
                onChange={handleChange}
                style={{ paddingLeft: '42px' }}
                autoComplete="name"
              />
            </div>
          </div>

          {/* Email */}
          <div>
            <label className="label" htmlFor="email">Email</label>
            <div style={{ position: 'relative' }}>
              <Mail size={16} style={{
                position: 'absolute', left: '14px', top: '50%',
                transform: 'translateY(-50%)', color: 'var(--text-muted)',
              }} />
              <input
                id="email"
                className="input"
                type="email"
                name="email"
                placeholder="you@example.com"
                value={form.email}
                onChange={handleChange}
                style={{ paddingLeft: '42px' }}
                autoComplete="email"
              />
            </div>
          </div>

          {/* Password */}
          <div>
            <label className="label" htmlFor="password">Password</label>
            <div style={{ position: 'relative' }}>
              <Lock size={16} style={{
                position: 'absolute', left: '14px', top: '50%',
                transform: 'translateY(-50%)', color: 'var(--text-muted)',
              }} />
              <input
                id="password"
                className="input"
                type={showPassword ? 'text' : 'password'}
                name="password"
                placeholder="Min. 6 characters"
                value={form.password}
                onChange={handleChange}
                style={{ paddingLeft: '42px', paddingRight: '42px' }}
                autoComplete="new-password"
              />
              <button type="button" onClick={() => setShowPassword(!showPassword)}
                className="btn btn-ghost"
                style={{ position: 'absolute', right: '8px', top: '50%', transform: 'translateY(-50%)', padding: '4px' }}>
                {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
            {/* Password Strength */}
            {form.password && (
              <div style={{ marginTop: '8px' }}>
                <div style={{ display: 'flex', gap: '4px', marginBottom: '4px' }}>
                  {[1, 2, 3, 4, 5].map((i) => (
                    <div key={i} style={{
                      height: '3px', flex: 1,
                      borderRadius: '2px',
                      background: i <= strength.score ? strength.color : 'var(--bg-input)',
                      transition: 'background 0.3s ease',
                    }} />
                  ))}
                </div>
                <p style={{ fontSize: '11px', color: strength.color }}>{strength.label} password</p>
              </div>
            )}
          </div>

          <button
            type="submit"
            className="btn btn-primary"
            disabled={loading}
            style={{ justifyContent: 'center', padding: '14px', fontSize: '15px' }}
          >
            {loading ? <><div className="spinner" />Creating account...</> : 'Create Free Account'}
          </button>
        </form>

        <p style={{ textAlign: 'center', marginTop: '20px', fontSize: '13px', color: 'var(--text-secondary)' }}>
          Already have an account?{' '}
          <Link to="/login" style={{ color: 'var(--accent-light)', fontWeight: '600' }}>Sign in</Link>
        </p>
      </div>
    </div>
  );
};

export default RegisterPage;
